mapper.update:
UPDATE
	mst.tb_req_board A
SET

		A.rboard_title = #{rboardTitle, jdbcType=VARCHAR}


		,A.rboard_division = #{rboardDivision, jdbcType=VARCHAR}


		,A.rboard_desire_date = #{rboardDesireDate, jdbcType=TIMESTAMP}


		,A.rboard_purpose_request = #{rboardPurposeRequest, jdbcType=VARCHAR}


		,A.rboard_importance = #{rboardImportance, jdbcType=VARCHAR}


		,A.rboard_content = #{rboardContent, jdbcType=VARCHAR}


		,A.dcreate_dt = #{rboardDcreateDt, jdbcType=TIMESTAMP}


		,A.screate_id = #{rboardScreateId, jdbcType=VARCHAR}


		,A.smodify_id = #{rboardSModifyId, jdbcType=TIMESTAMP}

	,A.dmodify_dt = sysdate
WHERE
	A.seq = #{seq, jdbcType=BIGINT}

UPDATE
	mst.tb_req_board_reply B
SET

		B.rboard_progress = #{rboardProgress, jdbcType=VARCHAR}


		,B.rboard_action_detail = #{rboardActionDetail, jdbcType=VARCHAR}


		,B.rboard_expected_date = #{rboardExpectedDate, jdbcType=TIMESTAMP}


		,B.smodify_id = #{rboardSModifyId, jdbcType=TIMESTAMP}

	,B.dmodify_dt = sysdate
WHERE
	B.rboard_seq = #{rboardSeq, jdbcType=BIGINT}

